if (! function_exists('scheduled_report')) {
    function scheduled_report($hn_stories = null, $weather_city = null, $github_topic = null, $rss_url = null, $title = null, $filename = null, $timeout = null, $max_rss_items = null)
    {
            $hn_stories = $hn_stories ?? 10;
            $weather_city = $weather_city ?? '';
            $github_topic = $github_topic ?? '';
            $rss_url = $rss_url ?? '';
            $title = $title ?? '';
            $filename = $filename ?? '';
            $timeout = $timeout ?? 15;
            $max_rss_items = $max_rss_items ?? 10;

            $hn_stories = max(0, min(30, (int)$hn_stories));
            $timeout = max(5, min(30, (int)$timeout));
            $max_rss_items = max(1, min(20, (int)$max_rss_items));

            $workspace = __DIR__ . '/../workspace';
            if (!is_dir($workspace)) @mkdir($workspace, 0777, true);

            // Helper: fetch JSON from a URL
            $fetch_json = function($url, $t) {
                $ctx = stream_context_create([
                    'http' => ['method' => 'GET', 'timeout' => $t, 'header' => "User-Agent: scheduled_report/1.0\r\n", 'ignore_errors' => true],
                    'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
                ]);
                $body = @file_get_contents($url, false, $ctx);
                if ($body === false) return ['error' => error_get_last()['message'] ?? 'fetch failed', 'success' => false];
                $status = 200;
                if (isset($http_response_header)) {
                    foreach ($http_response_header as $h) {
                        if (preg_match('#^HTTP/\d+\.\d+ (\d+)#', $h, $m)) { $status = (int)$m[1]; break; }
                    }
                }
                if ($status >= 400) return ['error' => "HTTP $status", 'status' => $status, 'success' => false];
                $data = @json_decode($body, true);
                if ($data === null) return ['error' => 'Invalid JSON', 'success' => false];
                return ['data' => $data, 'status' => $status, 'success' => true];
            };

            // Helper: fetch text (for RSS/HTML)
            $fetch_text = function($url, $t) {
                $ctx = stream_context_create([
                    'http' => ['method' => 'GET', 'timeout' => $t, 'header' => "User-Agent: scheduled_report/1.0\r\n", 'ignore_errors' => true],
                    'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
                ]);
                $body = @file_get_contents($url, false, $ctx);
                if ($body === false) return ['error' => error_get_last()['message'] ?? 'fetch failed', 'success' => false];
                return ['data' => $body, 'success' => true];
            };

            $sections = [];
            $errors = [];
            $now = gmdate('Y-m-d H:i:s');
            $now_ts = time();

            // ---- HackerNews ----
            $hn_items = [];
            if ($hn_stories > 0) {
                $hn_result = $fetch_json('https://hacker-news.firebaseio.com/v0/topstories.json', $timeout);
                if (!$hn_result['success']) {
                    $errors[] = 'HackerNews: ' . ($hn_result['error'] ?? 'unknown');
                } else {
                    $ids = array_slice($hn_result['data'], 0, $hn_stories);
                    foreach ($ids as $id) {
                        $item = $fetch_json("https://hacker-news.firebaseio.com/v0/item/$id.json", $timeout);
                        if (!$item['success'] || !is_array($item['data'])) continue;
                        $s = $item['data'];
                        $ts = $s['time'] ?? 0;
                        $time_ago = '';
                        if ($ts > 0) {
                            $diff = $now_ts - $ts;
                            if ($diff < 3600) $time_ago = floor($diff / 60) . 'm ago';
                            elseif ($diff < 86400) $time_ago = floor($diff / 3600) . 'h ago';
                            else $time_ago = floor($diff / 86400) . 'd ago';
                        }
                        $hn_items[] = [
                            'title' => $s['title'] ?? '[deleted]',
                            'url' => $s['url'] ?? "https://news.ycombinator.com/item?id=$id",
                            'score' => $s['score'] ?? 0,
                            'author' => $s['by'] ?? '?',
                            'comments' => $s['descendants'] ?? 0,
                            'time_ago' => $time_ago,
                        ];
                        usleep(30000);
                    }
                }
            }

            // ---- Weather ----
            $weather_data = null;
            if (!empty($weather_city)) {
                // Geocode
                $geo = $fetch_json('https://geocoding-api.open-meteo.com/v1/search?name=' . urlencode($weather_city) . '&count=1&language=en&format=json', $timeout);
                if (!$geo['success']) {
                    $errors[] = 'Weather geocoding: ' . ($geo['error'] ?? 'unknown');
                } elseif (!isset($geo['data']['results'][0])) {
                    $errors[] = "Weather: city '$weather_city' not found";
                } else {
                    $loc = $geo['data']['results'][0];
                    $lat = $loc['latitude'];
                    $lon = $loc['longitude'];
                    $city_name = $loc['name'];
                    $country = $loc['country'] ?? '';
                    $tz = $loc['timezone'] ?? 'auto';

                    // Fetch weather
                    $wurl = "https://api.open-meteo.com/v1/forecast?latitude=$lat&longitude=$lon&current=temperature_2m,apparent_temperature,precipitation,weather_code,wind_speed_10m,relative_humidity_2m,pressure_msl,uv_index&daily=temperature_2m_max,temperature_2m_min,precipitation_sum,precipitation_probability_max,weather_code,wind_speed_10m_max,sunrise,sunset&timezone=" . urlencode($tz) . "&forecast_days=3";
                    $w = $fetch_json($wurl, $timeout);
                    if (!$w['success']) {
                        $errors[] = 'Weather data: ' . ($w['error'] ?? 'unknown');
                    } else {
                        $wd = $w['data'];
                        $wmo = [0=>'☀️ Clear',1=>'🌤️ Mainly clear',2=>'⛅ Partly cloudy',3=>'☁️ Overcast',45=>'🌫️ Foggy',48=>'🌫️ Rime fog',51=>'🌦️ Light drizzle',53=>'🌦️ Moderate drizzle',55=>'🌧️ Dense drizzle',61=>'🌧️ Slight rain',63=>'🌧️ Moderate rain',65=>'🌧️ Heavy rain',71=>'🌨️ Slight snow',73=>'🌨️ Moderate snow',75=>'❄️ Heavy snow',80=>'🌦️ Rain showers',81=>'🌧️ Mod. showers',82=>'🌧️ Heavy showers',95=>'⛈️ Thunderstorm',96=>'⛈️ Hail',99=>'⛈️ Heavy hail'];
                        $cur = $wd['current'] ?? [];
                        $daily = $wd['daily'] ?? [];
                        $weather_data = [
                            'city' => "$city_name, $country",
                            'current' => $cur ? [
                                'temp' => ($cur['temperature_2m'] ?? '?') . ($wd['current_units']['temperature_2m'] ?? '°C'),
                                'feels_like' => ($cur['apparent_temperature'] ?? '?') . ($wd['current_units']['apparent_temperature'] ?? '°C'),
                                'humidity' => ($cur['relative_humidity_2m'] ?? '?') . ($wd['current_units']['relative_humidity_2m'] ?? '%'),
                                'precip' => ($cur['precipitation'] ?? '0') . ($wd['current_units']['precipitation'] ?? 'mm'),
                                'wind' => ($cur['wind_speed_10m'] ?? '?') . ($wd['current_units']['wind_speed_10m'] ?? 'km/h'),
                                'pressure' => ($cur['pressure_msl'] ?? '?') . ($wd['current_units']['pressure_msl'] ?? 'hPa'),
                                'weather' => $wmo[$cur['weather_code'] ?? -1] ?? "Code " . ($cur['weather_code'] ?? '?'),
                            ] : null,
                            'forecast' => [],
                        ];
                        if (!empty($daily['time'])) {
                            for ($i = 0; $i < count($daily['time']); $i++) {
                                $weather_data['forecast'][] = [
                                    'date' => $daily['time'][$i],
                                    'high' => ($daily['temperature_2m_max'][$i] ?? '?') . ($wd['daily_units']['temperature_2m_max'] ?? '°C'),
                                    'low' => ($daily['temperature_2m_min'][$i] ?? '?') . ($wd['daily_units']['temperature_2m_min'] ?? '°C'),
                                    'precip' => ($daily['precipitation_sum'][$i] ?? 0) . ($wd['daily_units']['precipitation_sum'] ?? 'mm'),
                                    'precip_prob' => ($daily['precipitation_probability_max'][$i] ?? 0) . ($wd['daily_units']['precipitation_probability_max'] ?? '%'),
                                    'wind' => ($daily['wind_speed_10m_max'][$i] ?? '?') . ($wd['daily_units']['wind_speed_10m_max'] ?? 'km/h'),
                                    'weather' => $wmo[$daily['weather_code'][$i] ?? -1] ?? '?',
                                ];
                            }
                        }
                    }
                }
            }

            // ---- GitHub trending (search by topic, sorted by stars) ----
            $github_items = [];
            if (!empty($github_topic)) {
                $query = urlencode($github_topic);
                $gh = $fetch_json("https://api.github.com/search/repositories?q=$query&sort=stars&order=desc&per_page=10", $timeout);
                if (!$gh['success']) {
                    $errors[] = 'GitHub: ' . ($gh['error'] ?? 'unknown');
                } elseif (isset($gh['data']['items'])) {
                    foreach ($gh['data']['items'] as $repo) {
                        $github_items[] = [
                            'name' => $repo['full_name'],
                            'url' => $repo['html_url'],
                            'description' => $repo['description'] ?? '(no description)',
                            'stars' => $repo['stargazers_count'] ?? 0,
                            'forks' => $repo['forks_count'] ?? 0,
                            'language' => $repo['language'] ?? 'N/A',
                            'updated' => $repo['updated_at'] ?? '',
                        ];
                    }
                }
            }

            // ---- RSS Feed ----
            $rss_items = [];
            if (!empty($rss_url)) {
                $xml_result = $fetch_text($rss_url, $timeout);
                if (!$xml_result['success']) {
                    $errors[] = 'RSS: ' . ($xml_result['error'] ?? 'unknown');
                } else {
                    $xml = @simplexml_load_string($xml_result['data']);
                    if ($xml === false) {
                        $errors[] = 'RSS: failed to parse XML';
                    } else {
                        $feed_title = (string)($xml->channel->title ?? $xml->title ?? 'Feed');
                        $entries = [];
                        if (isset($xml->channel->item)) {
                            $entries = $xml->channel->item;
                        } elseif (isset($xml->entry)) {
                            $entries = $xml->entry;
                        }
                        $count = 0;
                        foreach ($entries as $entry) {
                            if ($count >= $max_rss_items) break;
                            $title = (string)($entry->title ?? 'Untitled');
                            $link = (string)($entry->link->attributes()->href ?? $entry->link ?? '');
                            if (empty($link) && isset($entry->link) && !($entry->link instanceof \SimpleXMLElement)) {
                                $link = (string)$entry->link;
                            }
                            $pubDate = (string)($entry->pubDate ?? $entry->published ?? $entry->updated ?? '');
                            $desc = (string)($entry->description ?? $entry->summary ?? '');
                            $desc = strip_tags($desc);
                            if (strlen($desc) > 200) $desc = substr($desc, 0, 200) . '...';
                            $rss_items[] = [
                                'title' => $title,
                                'link' => $link,
                                'date' => $pubDate,
                                'snippet' => $desc,
                            ];
                            $count++;
                        }
                    }
                }
            }

            // ---- Build the markdown report ----
            $auto_title = $title ?: "Daily Digest — " . gmdate('F j, Y');
            $sep = str_repeat('=', 60);

            $md = [];
            $md[] = "# $auto_title";
            $md[] = "";
            $md[] = "**Generated:** $now UTC";
            $md[] = "";
            $md[] = $sep;
            $md[] = "";

            $sources_used = 0;

            // Section: HackerNews
            if (!empty($hn_items)) {
                $sources_used++;
                $md[] = "## 📰 HackerNews — Top Stories";
                $md[] = "";
                foreach ($hn_items as $i => $item) {
                    $rank = $i + 1;
                    $md[] = "{$rank}. [{$item['title']}]({$item['url']})";
                    $md[] = "   ⭐ {$item['score']} points by {$item['author']} | 💬 {$item['comments']} comments | {$item['time_ago']}";
                    $md[] = "";
                }
                $md[] = $sep;
                $md[] = "";
            }

            // Section: Weather
            if ($weather_data !== null) {
                $sources_used++;
                $md[] = "## 🌤️ Weather — {$weather_data['city']}";
                $md[] = "";
                if ($weather_data['current']) {
                    $c = $weather_data['current'];
                    $md[] = "**Current:** {$c['weather']}";
                    $md[] = "";
                    $md[] = "| Metric | Value |";
                    $md[] = "|--------|-------|";
                    $md[] = "| Temperature | {$c['temp']} (feels like {$c['feels_like']}) |";
                    $md[] = "| Humidity | {$c['humidity']} |";
                    $md[] = "| Precipitation | {$c['precip']} |";
                    $md[] = "| Wind Speed | {$c['wind']} |";
                    $md[] = "| Pressure | {$c['pressure']} |";
                    $md[] = "";
                }
                if (!empty($weather_data['forecast'])) {
                    $md[] = "**3-Day Forecast:**";
                    $md[] = "";
                    $md[] = "| Date | Condition | High | Low | Precip | Wind |";
                    $md[] = "|------|-----------|------|-----|--------|------|";
                    foreach ($weather_data['forecast'] as $f) {
                        $md[] = "| {$f['date']} | {$f['weather']} | {$f['high']} | {$f['low']} | {$f['precip']} ({$f['precip_prob']}) | {$f['wind']} |";
                    }
                    $md[] = "";
                }
                $md[] = $sep;
                $md[] = "";
            }

            // Section: GitHub
            if (!empty($github_items)) {
                $sources_used++;
                $md[] = "## 💻 GitHub — Trending: \"{$github_topic}\"";
                $md[] = "";
                $md[] = "| # | Repository | ⭐ Stars | 🍴 Forks | Language |";
                $md[] = "|---|-----------|---------|---------|----------|";
                foreach ($github_items as $i => $repo) {
                    $rank = $i + 1;
                    $md[] = "| {$rank} | [{$repo['name']}]({$repo['url']}) | {$repo['stars']} | {$repo['forks']} | {$repo['language']} |";
                }
                $md[] = "";
                $md[] = $sep;
                $md[] = "";
            }

            // Section: RSS
            if (!empty($rss_items)) {
                $sources_used++;
                $md[] = "## 📡 RSS Feed — Recent Items";
                $md[] = "";
                foreach ($rss_items as $item) {
                    $link_part = !empty($item['link']) ? "[{$item['title']}]({$item['link']})" : $item['title'];
                    $date_part = !empty($item['date']) ? " ({$item['date']})" : '';
                    $md[] = "- **{$link_part}**{$date_part}";
                    if (!empty($item['snippet'])) {
                        $md[] = "  > {$item['snippet']}";
                    }
                    $md[] = "";
                }
                $md[] = $sep;
                $md[] = "";
            }

            // Section: Errors
            if (!empty($errors)) {
                $md[] = "## ⚠️ Source Errors";
                $md[] = "";
                foreach ($errors as $err) {
                    $md[] = "- ❌ {$err}";
                }
                $md[] = "";
                $md[] = $sep;
                $md[] = "";
            }

            // Footer
            $md[] = "";
            $md[] = "---";
            $md[] = "*Report generated by [scheduled_report](https://github.com/) — {$now} UTC*";
            $md[] = "";
            $md[] = "**Sources consulted:** {$sources_used}" . (!empty($errors) ? " | **Errors:** " . count($errors) : "");
            $md[] = "";

            $report_content = implode("\n", $md);

            // Write to file
            $auto_filename = $filename ?: 'report-' . gmdate('Y-m-d-His') . '.md';
            // Ensure .md extension
            if (!str_ends_with($auto_filename, '.md')) $auto_filename .= '.md';
            $output_path = $workspace . '/' . basename($auto_filename);

            $written = @file_put_contents($output_path, $report_content);
            if ($written === false) {
                return [
                    'success' => false,
                    'error' => 'Failed to write report to ' . $output_path,
                    'report_length' => strlen($report_content),
                    'sources_used' => $sources_used,
                    'sections' => [
                        'hackernews_items' => count($hn_items),
                        'weather' => $weather_data !== null,
                        'github_items' => count($github_items),
                        'rss_items' => count($rss_items),
                    ],
                    'errors' => $errors,
                ];
            }

            return [
                'success' => true,
                'report_file' => 'storage/agent/workspace/' . basename($auto_filename),
                'report_size_bytes' => $written,
                'report_title' => $auto_title,
                'generated_at' => $now . ' UTC',
                'sources_used' => $sources_used,
                'sections' => [
                    'hackernews_items' => count($hn_items),
                    'weather_reported' => $weather_data !== null,
                    'github_items' => count($github_items),
                    'rss_items' => count($rss_items),
                ],
                'errors' => $errors,
                'has_errors' => count($errors) > 0,
            ];
    }
}
